import React, { useRef, useEffect, useState } from 'react';

function VisualExplainCard({ imageBase64, steps, audioChunks }) {
    const canvasRef = useRef(null);
    const [currentStep, setCurrentStep] = useState(0);
    const [isPlaying, setIsPlaying] = useState(false);
    const audioRefs = useRef([]);
    const timers = useRef([]);

    // 安全处理：确保数据是数组
    const safeSteps = Array.isArray(steps) ? steps : [];
    const safeAudioChunks = Array.isArray(audioChunks) ? audioChunks : [];

    // 初始化音频对象
    useEffect(() => {
        audioRefs.current = safeAudioChunks.map(b64 => {
            const audio = new Audio(`data:audio/mp3;base64,${b64}`);
            audio.preload = 'auto';
            return audio;
        });
        return () => {
            audioRefs.current.forEach(a => {
                a.pause();
                a.src = '';
            });
            timers.current.forEach(clearTimeout);
        };
    }, [safeAudioChunks]);

    // 绘制图片及标注
    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas || safeSteps.length === 0) return;
        const ctx = canvas.getContext('2d');
        const img = new Image();
        img.src = `data:image/png;base64,${imageBase64}`;
        img.onload = () => {
            canvas.width = img.width;
            canvas.height = img.height;
            ctx.clearRect(0, 0, canvas.width, canvas.height);
            ctx.drawImage(img, 0, 0);

            const step = safeSteps[currentStep] || { annotations: [] };
            const annotations = Array.isArray(step.annotations) ? step.annotations : [];
            annotations.forEach(anno => {
                ctx.save();
                ctx.strokeStyle = anno.color || 'red';
                ctx.fillStyle = anno.color || 'red';
                ctx.lineWidth = 3;
                ctx.font = '18px Arial';
                const x1 = (anno.x1 || 0) * img.width;
                const y1 = (anno.y1 || 0) * img.height;
                const x2 = (anno.x2 || 0) * img.width;
                const y2 = (anno.y2 || 0) * img.height;

                if (anno.type === 'line') {
                    ctx.beginPath();
                    ctx.moveTo(x1, y1);
                    ctx.lineTo(x2, y2);
                    ctx.stroke();
                } else if (anno.type === 'circle') {
                    ctx.beginPath();
                    ctx.arc(x1, y1, (anno.r || 30) * (img.width / 800), 0, 2 * Math.PI);
                    ctx.stroke();
                } else if (anno.type === 'text') {
                    ctx.fillText(anno.label || '', x1, y1);
                } else if (anno.type === 'rect') {
                    ctx.strokeRect(x1, y1, x2 - x1, y2 - y1);
                }
                ctx.restore();
            });
        };
    }, [currentStep, safeSteps, imageBase64]);

    // 播放逻辑
    const startPlayback = () => {
        if (audioRefs.current.length === 0) return;
        stopPlayback();
        setIsPlaying(true);

        let stepIndex = 0;
        setCurrentStep(stepIndex);

        const playNext = () => {
            if (stepIndex >= audioRefs.current.length) {
                setIsPlaying(false);
                setCurrentStep(0);
                return;
            }
            const audio = audioRefs.current[stepIndex];
            if (!audio) {
                stepIndex++;
                playNext();
                return;
            }

            audio.currentTime = 0;
            audio.play().catch(() => { });

            const duration = (audio.duration || 4) * 1000;
            timers.current.push(setTimeout(() => {
                stepIndex++;
                if (stepIndex < safeSteps.length) {
                    setCurrentStep(stepIndex);
                }
                playNext();
            }, duration));
        };

        playNext();
    };

    const stopPlayback = () => {
        audioRefs.current.forEach(a => a.pause());
        timers.current.forEach(t => clearTimeout(t));
        setIsPlaying(false);
    };

    if (safeSteps.length === 0) {
        return (
            <div className="bg-white rounded-2xl p-4 shadow-md my-2">
                <p className="text-gray-500 text-sm">讲解内容正在准备中...</p>
            </div>
        );
    }

    return (
        <div className="bg-white rounded-2xl p-4 shadow-md my-2 max-w-full">
            <div className="flex justify-between items-center mb-2">
                <h3 className="font-semibold text-gray-800">👩‍🏫 AI 超拟人老师</h3>
                <div className="flex gap-2">
                    <button
                        onClick={isPlaying ? stopPlayback : startPlayback}
                        className={`px-4 py-1.5 rounded-full text-xs font-semibold ${isPlaying ? 'bg-red-100 text-red-700 hover:bg-red-200' : 'bg-blue-100 text-blue-700 hover:bg-blue-200'}`}
                    >
                        {isPlaying ? '⏹ 停止' : '▶ 播放讲解'}
                    </button>
                </div>
            </div>

            <div className="relative bg-gray-100 rounded-lg overflow-hidden">
                <canvas ref={canvasRef} className="w-full" style={{ maxHeight: '60vh' }} />
            </div>

            {safeSteps[currentStep] && (
                <div className="mt-3 p-3 bg-blue-50 rounded-xl border border-blue-200">
                    <p className="text-sm text-gray-800 font-medium">
                        <span className="text-blue-600 mr-2">步骤 {currentStep + 1}/{safeSteps.length}</span>
                        {safeSteps[currentStep].text}
                    </p>
                </div>
            )}

            <div className="flex justify-center gap-2 mt-4">
                {safeSteps.map((_, idx) => (
                    <button
                        key={idx}
                        onClick={() => {
                            if (isPlaying) stopPlayback();
                            setCurrentStep(idx);
                        }}
                        className={`w-3 h-3 rounded-full transition ${idx === currentStep ? 'bg-blue-500 scale-125' : 'bg-gray-300'}`}
                    />
                ))}
            </div>
        </div>
    );
}

export default VisualExplainCard;
